// LLM citation surfaces: /llms.txt + /llms-full.txt.
//
// Mirrors the convention popularised by llmstxt.org: a compact `llms.txt`
// pointing LLMs at the canonical doc URLs + a `llms-full.txt` that
// inlines every per-page mirror as one long markdown document an agent
// can paste into a context window.
//
// Inputs:
//  - `src/lib/sitemap-manifest.json`  (route → ISO mtime, emitted by
//    docs-kit's sitemapManifestPlugin)
//  - `static/docs/<slug>.md`          (per-page mirrors, emitted by
//    docs-kit's docMirrorsPlugin)
//
// Outputs (gitignored, regenerated by `pnpm build`):
//  - `static/llms.txt`
//  - `static/llms-full.txt`
//
// Run via `pnpm llms` or automatically through the `build` script (after
// `generate-doc-mirrors`).

import { existsSync } from 'node:fs'
import { mkdir, readFile, readdir, writeFile } from 'node:fs/promises'
import { join, resolve as resolvePath } from 'node:path'

const ROOT = process.cwd()
const DOCS_DIR = resolvePath(ROOT, 'static', 'docs')
const SITEMAP = resolvePath(ROOT, 'src', 'lib', 'sitemap-manifest.json')
const OUT_INDEX = resolvePath(ROOT, 'static', 'llms.txt')
const OUT_FULL = resolvePath(ROOT, 'static', 'llms-full.txt')
const SITE_URL = 'https://table.svelte.page'
const PKG_NAME = '@humanspeak/svelte-headless-table'

/** Slug used by docMirrorsPlugin to write `<slug>.md` for a `/docs/<...>` route.
 *  Matches the flat-slug rule the plugin uses: nested paths get hyphenated,
 *  and `/docs` itself becomes `index`. */
function routeToSlug(route) {
    const rel = route.replace(/^\/docs\/?/, '').replace(/^\/+|\/+$/g, '')
    if (rel === '') return 'index'
    return rel.replace(/\//g, '-')
}

/** Pretty title from a slug: `api-table` → `Api Table`. The actual <h1>
 *  inside each .md is the source of truth; this fallback is only used in
 *  the compact index when we haven't loaded the file yet. */
function slugToTitle(slug) {
    return slug
        .split('-')
        .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
        .join(' ')
}

async function loadDocRoutes() {
    let manifest
    try {
        manifest = JSON.parse(await readFile(SITEMAP, 'utf8'))
    } catch {
        // Sitemap not generated yet — fall back to discovering .md files.
        const files = existsSync(DOCS_DIR) ? await readdir(DOCS_DIR) : []
        return files
            .filter((f) => f.endsWith('.md'))
            .map((f) => f.replace(/\.md$/, ''))
            .sort()
            .map((slug) => ({
                slug,
                route: slug === 'index' ? '/docs' : `/docs/${slug.replace(/-/g, '/')}`
            }))
    }
    return Object.keys(manifest)
        .filter((r) => r === '/docs' || r.startsWith('/docs/'))
        .sort()
        .map((route) => ({ route, slug: routeToSlug(route) }))
}

/** Pull the YAML frontmatter title (or the leading `# ` line) out of a
 *  mirror file. Falls back to the slug-derived title. */
async function readDocMeta(slug) {
    const path = join(DOCS_DIR, `${slug}.md`)
    if (!existsSync(path)) {
        return { title: slugToTitle(slug), body: '' }
    }
    const src = await readFile(path, 'utf8')
    const h1 = src.match(/^#\s+(.+?)\s*$/m)
    return {
        title: h1 ? h1[1].trim() : slugToTitle(slug),
        body: src
    }
}

async function build() {
    const routes = await loadDocRoutes()
    const entries = await Promise.all(
        routes.map(async ({ route, slug }) => {
            const meta = await readDocMeta(slug)
            return { route, slug, ...meta }
        })
    )

    await mkdir(resolvePath(ROOT, 'static'), { recursive: true })

    // ── /llms.txt ───────────────────────────────────────────────────
    // Compact index: project blurb + link table. Agents typically fetch
    // this first to discover what's available before pulling specific
    // doc pages.
    const indexBody = [
        `# ${PKG_NAME}`,
        '',
        `> A powerful, headless table library for Svelte 5. Composable plugins for sorting, filtering, pagination, grouping, expansion, selection, column resizing, sub-rows, and virtual scroll. TypeScript-first, MIT.`,
        '',
        `Canonical docs root: ${SITE_URL}/docs`,
        `Per-page markdown mirrors: ${SITE_URL}/docs/<slug>.md`,
        `Full reference (single document): ${SITE_URL}/llms-full.txt`,
        '',
        '## Documentation',
        '',
        ...entries.map((e) => `- [${e.title}](${SITE_URL}${e.route}.md) — ${SITE_URL}${e.route}`),
        ''
    ].join('\n')
    await writeFile(OUT_INDEX, indexBody, 'utf8')

    // ── /llms-full.txt ──────────────────────────────────────────────
    // Inline every mirror in one file, separated by a thin rule so an
    // agent can find boundaries. Optimised for "drop the whole library
    // into one context window" prompts.
    const fullBody = [
        `# ${PKG_NAME} — full reference`,
        '',
        `> Concatenated dump of every doc page under ${SITE_URL}/docs.`,
        `> Each section is bounded by an HTML comment with the source URL.`,
        '',
        '---',
        '',
        ...entries.map((e) => e.body.trim()),
        ''
    ].join('\n\n')
    await writeFile(OUT_FULL, fullBody, 'utf8')

    console.log(`Wrote ${entries.length} entries to ${OUT_INDEX} + ${OUT_FULL}`)
}

build().catch((err) => {
    console.error(err)
    process.exit(1)
})
